package metadata

import (
	"fmt"
	"io"
	"strings"
)

func renderHeader(w io.Writer, category Category, providerName, resourceType, subcategory, description string) error {
	if _, err := io.WriteString(w, `---
# generated by https://github.com/magodo/terraform-plugin-framework-docs
`); err != nil {
		return err
	}

	if category == CategoryProvider {
		if _, err := fmt.Fprintf(w, `page_title: "%s %s"
`, providerName, category); err != nil {
			return err
		}
	} else {
		if _, err := fmt.Fprintf(w, `page_title: "%s %s - terraform-provider-%s"
subcategory: "%s"
`, resourceType, category, providerName, subcategory); err != nil {
			return err
		}
	}

	// Indent description
	indentedDescriptionLines := []string{}
	for line := range strings.SplitSeq(description, "\n") {
		if strings.TrimSpace(line) != "" {
			line = "  " + line
		}
		indentedDescriptionLines = append(indentedDescriptionLines, line)
	}

	if _, err := fmt.Fprintf(w, `description: |-
%s
---
`, strings.Join(indentedDescriptionLines, "\n")); err != nil {
		return err
	}
	return nil
}
